16	//
17	// RBTDRK — gauntlet canonical-establish fixture (§2 of release qualification)
18	//
19	// Establishes long-lived canonical state the gauntlet's downstream fixtures
20	// inherit:
21	//   1. depot_levy        — install canonical RBRR prefixes; levy a fresh canest depot
22	//   2. governor_mantle   — mantle governor against the canonical depot
23	//   3. retriever_invest  — invest a canonical retriever SA + access-probe
24	//   4. director_invest   — invest a canonical director SA + access-probe
25	//
26	// Disposition: StateProgressing. Each case carries a precondition probe via
27	// rbtdrb_Probe so a-la-carte single-case rerun fails cleanly when an earlier
28	// case's state is absent. Tabtarget invocations are responsible for waiting
29	// out their own propagation (no separate iam-propagation-wait case).
30	
31	use std::path::{Path, PathBuf};
32	use std::process::Command;
33	
34	use crate::case;
35	use crate::rbtdrb_probe::{rbtdrb_assert, rbtdrb_Probe};
36	use crate::rbtdrc_crucible::rbtdrc_with_ctx;
37	use crate::rbtdre_engine::{rbtdre_Case, rbtdre_Disposition, rbtdre_Fixture, rbtdre_Verdict};
38	use crate::rbtdri_invocation::{
39	    rbtdri_invoke_global, rbtdri_read_burv_fact, rbtdri_Context,
40	    rbtdri_InvokeResult, RBTDRI_BURV_OUTPUT_SUBDIR,
41	};
42	use crate::rbtdgc_consts::{
43	    RBTDGC_DIVEST_DIRECTOR,
44	    RBTDGC_DIVEST_RETRIEVER,
45	    RBTDGC_INVEST_DIRECTOR,
46	    RBTDGC_INVEST_RETRIEVER,
47	    RBTDGC_LEVY_DEPOT,
48	    RBTDGC_LIST_DEPOT,
49	    RBTDGC_MANTLE_GOVERNOR,
50	    RBTDGC_RBRA_FILE,
51	    RBTDGC_RBRD_FILE,
52	    RBTDGC_RBRR_FILE,
53	    RBTDGC_ROLE_ASSAY,
54	    RBTDGC_ROLE_DIRECTOR,
55	    RBTDGC_ROLE_GOVERNOR,
56	    RBTDGC_ROLE_RETRIEVER,
57	};
58	use crate::rbtdrm_manifest::{
59	    rbtdrm_credential_check_colophon,
60	    RBTDRM_FIXTURE_CANONICAL_ESTABLISH,
61	    RBTDRM_FIXTURE_CANONICAL_INVEST,
62	};
63	
64	// ── Canonical-fixture identities ─────────────────────────────
65	
66	/// Canonical RBRR prefix bases installed by case 1. Distinct from pristine's
67	/// throwaway prefix bases (prlc/prlr); per-station tincture from BURS is
68	/// composed in at runtime so parallel-station runs land in disjoint cloud
69	/// names. Case 2's probe detects canonical state by reading the moniker's
70	/// family stem (also tinctured) from rbrr.env.
71	pub(crate) const RBTDRK_CANONICAL_CLOUD_BASE: &str = "canc";
72	pub(crate) const RBTDRK_CANONICAL_RUNTIME_BASE: &str = "canr";
73	
74	/// Family-stem base for canonical depots; six-digit auto-increment suffix per
75	/// run. Depots persist post-success for operator inspection; reruns pick the
76	/// next free suffix by walking depot_list output. Per-station tincture is
77	/// composed in at runtime so each station's monikers fact-file-walk against
78	/// a disjoint family stem. Era-bumped past `canest` and `canest2` to
79	/// side-step pending-delete projectId reservations from burned-bridges
80	/// teardown. The `canest2` bump was forced when the prior gmail-identity
81	/// payor's deleted `canest2bhm100000` depot held the global projectId in
82	/// DELETE_REQUESTED: project IDs are globally unique and reserved ~30 days
83	/// post-delete, and the active-only, single-identity allocator re-derives a
84	/// reserved ID it can neither see nor own.
85	pub(crate) const RBTDRK_FAMILY_STEM_BASE: &str = "canest3";
86	
87	/// Static identities for the canonical SA cycle. Stable across runs because
88	/// each run uses a fresh canest depot project.
89	const RBTDRK_IDENTITY_RETRIEVER: &str = "canest-ret";
90	const RBTDRK_IDENTITY_DIRECTOR: &str = "canest-dir";
91	
92	const RBTDRK_FAMILY_NUMERIC_FLOOR: u32 = 100000;
93	const RBTDRK_FAMILY_NUMERIC_WIDTH: usize = 6;
94	
95	// rbgp_depot_list emits fact files at
96	// `<cloud_prefix>/<moniker>.depot` (state) and
97	// `<cloud_prefix>/<moniker>.depot-project` (project_id). The cloud_prefix
98	// subdir prevents collisions between same-moniker depots under different
99	// cloud_prefixes.
100	const RBTDRK_FACT_EXT_DEPOT: &str = "depot";
101	const RBTDRK_FACT_EXT_DEPOT_PROJECT: &str = "depot-project";
102	const RBTDRK_FACT_GOVERNOR_SA_EMAIL: &str = "rbgp_fact_governor_sa_email";
103	
104	const RBTDRK_FIELD_RBRD_CLOUD_PREFIX: &str = "RBRD_CLOUD_PREFIX";
105	const RBTDRK_FIELD_RBRR_RUNTIME_PREFIX: &str = "RBRR_RUNTIME_PREFIX";
106	const RBTDRK_FIELD_RBRD_DEPOT_MONIKER: &str = "RBRD_DEPOT_MONIKER";
107	const RBTDRK_FIELD_RBRR_SECRETS_DIR: &str = "RBRR_SECRETS_DIR";
108	
109	// Bundled moorings paths — module-local aliases of the generated RBTDGC_*
110	// consts (projected from rbcc_Constants.sh), so the path values live in one place.
111	const RBTDRK_RBRR_FILE: &str = RBTDGC_RBRR_FILE;
112	const RBTDRK_RBRD_FILE: &str = RBTDGC_RBRD_FILE;
113	const RBTDRK_RBRA_FILE: &str = RBTDGC_RBRA_FILE;
114	
115	/// BURS station-file env var (exported by bul_launcher.sh) — absolute path
116	/// to the developer's burs.env. Source for BURS_TINCTURE.
117	const RBTDRK_ENV_STATION_FILE: &str = "BURD_STATION_FILE";
118	
119	/// Read BURS_TINCTURE from the station file resolved via BURD_STATION_FILE.
120	/// BURS validation upstream (zburs_enforce) guarantees the value is 1-3 chars
121	/// of lowercase alphanumeric starting with a letter.
122	pub(crate) fn rbtdrk_burs_tincture() -> Result<String, String> {
123	    let path_str = std::env::var(RBTDRK_ENV_STATION_FILE)
124	        .map_err(|_| format!("{} not set in environment", RBTDRK_ENV_STATION_FILE))?;
125	    let path = PathBuf::from(&path_str);
126	    rbtdrk_read_env_value(&path, "BURS_TINCTURE")
127	        .ok_or_else(|| format!("BURS_TINCTURE not in {}", path.display()))
128	}
129	
130	/// Compose canonical RBRD_CLOUD_PREFIX with the given tincture.
131	pub(crate) fn rbtdrk_canonical_cloud_prefix(tincture: &str) -> String {
132	    format!("{}{}-", RBTDRK_CANONICAL_CLOUD_BASE, tincture)
133	}
134	
135	/// Compose canonical RBRR_RUNTIME_PREFIX with the given tincture.
136	pub(crate) fn rbtdrk_canonical_runtime_prefix(tincture: &str) -> String {
137	    format!("{}{}-", RBTDRK_CANONICAL_RUNTIME_BASE, tincture)
138	}
139	
140	/// Compose canonical family stem with the given tincture.
141	pub(crate) fn rbtdrk_family_stem(tincture: &str) -> String {
142	    format!("{}{}", RBTDRK_FAMILY_STEM_BASE, tincture)
143	}
144	
145	// ── Helpers ──────────────────────────────────────────────────
146	
147	/// Read an env-file value or None if absent. Mirrors pristine's helper —
148	/// kept local to avoid coupling canonical-establish to pristine-lifecycle.
149	fn rbtdrk_read_env_value(path: &Path, key: &str) -> Option<String> {
150	    let content = std::fs::read_to_string(path).ok()?;
151	    let prefix = format!("{}=", key);
