17	// RBTDRD — dogfight cloud-build viability fixture
18	//
19	// Proves the cloud-depot build-and-retrieve path yields a *runnable*
20	// artifact, with no crucible apparatus. Standing-depot scenario fixture,
21	// sibling to canonical-invest in the operator-precondition family: it reuses
22	// a depot the operator has levied by hand (no levy, no unmake) and assumes a
23	// director + retriever already invested. It differs from the skirmish chain
24	// on the crucible axis — dogfight charges NO crucible. It proves only
25	// build → summon → run viability, not containment (the crucible's orthogonal
26	// concern).
27	//
28	// Single case, ordain → summon → run → abjure, threaded through one body. The
29	// busybox vessel is consumerless — no nameplate holds its hallmark, so there
30	// is no committed regime file to carry the ephemeral hallmark across a
31	// case boundary. The hallmark therefore lives as a local across the steps,
32	// the same structural choice rbtdrc_hallmark_lifecycle makes for the same
33	// reason. This fixture IS hallmark_lifecycle with the registry-inventory
34	// middle (audit/rekon) swapped for summon + a bare container-runtime run.
35	
36	use std::path::{Path, PathBuf};
37	use std::process::Command;
38	
39	use crate::case;
40	use crate::rbtdrb_probe::{rbtdrb_assert, rbtdrb_Probe};
41	use crate::rbtdrc_crucible::{
42	    rbtdrc_docker_inspect, rbtdrc_with_ctx, RBTDRC_ARK_BASENAME_IMAGE, RBTDRC_BUSYBOX_VESSEL_DIR,
43	    RBTDRC_FACT_ARK_STEM, RBTDRC_FACT_GAR_ROOT, RBTDRC_FACT_HALLMARK,
44	};
45	use crate::rbtdre_engine::{rbtdre_Case, rbtdre_Disposition, rbtdre_Fixture, rbtdre_Verdict};
46	use crate::rbtdri_invocation::{
47	    rbtdri_invoke_global, rbtdri_read_burv_fact, rbtdri_Context, RBTDRI_BURE_CONFIRM_KEY,
48	    RBTDRI_BURE_CONFIRM_SKIP,
49	};
50	use crate::rbtdrk_canonical::rbtdrk_canonical_rbra;
51	use crate::rbtdgc_consts::{
52	    RBTDGC_ABJURE_HALLMARK, RBTDGC_ORDAIN_HALLMARK, RBTDGC_ROLE_DIRECTOR, RBTDGC_SUMMON_HALLMARK,
53	};
54	
55	/// Container runtime for the bare executability proof. Hardcoded to docker;
56	/// podman is deferred to the Director-governed runtime-regime decision that
57	/// rides with ₣BS. This single named site is the future swap point — do NOT
58	/// add a regime field here now.
59	const RBTDRD_RUNTIME: &str = "docker";
60	
61	/// Degenerate command proving the summoned image is runnable. busybox's
62	/// default cmd is `sh`; passing an explicit `true` yields a clean exit-0
63	/// executability proof without spawning an interactive shell.
64	const RBTDRD_PROOF_CMD: &str = "true";
65	
66	// ── Probe ────────────────────────────────────────────────────
67	//
68	// Probes are pure `fn() -> Result<(), String>` per the rbtdrb_Probe shape and
69	// have no context, so they read the project root from current_dir() — theurge
70	// always launches from the project root.
71	
72	fn rbtdrd_probe_root() -> Result<PathBuf, String> {
73	    std::env::current_dir().map_err(|e| format!("cannot resolve project root: {}", e))
74	}
75	
76	/// Precondition: director RBRA present at the canonical secrets path —
77	/// evidence an operator has levied the standing depot and invested a director
78	/// (the role that ordains and abjures). Mirrors onboarding's governor-RBRA
79	/// probe shape. The retriever credential summon needs is not separately
80	/// probed; summon fails loud if it is absent.
81	fn rbtdrd_probe_director_rbra() -> Result<(), String> {
82	    let root = rbtdrd_probe_root()?;
83	    let path = rbtdrk_canonical_rbra(&root, RBTDGC_ROLE_DIRECTOR)?;
84	    if !path.exists() {
85	        return Err(format!("director RBRA absent at {}", path.display()));
86	    }
87	    Ok(())
88	}
89	
90	// ── Runtime run helper ───────────────────────────────────────
91	
92	/// Run `<runtime> run --rm <image_ref> <cmd>` and return Ok on exit 0. The
93	/// single site naming the container runtime — see RBTDRD_RUNTIME.
94	fn rbtdrd_runtime_run(image_ref: &str, cmd: &str, dir: &Path) -> Result<(), String> {
95	    let output = Command::new(RBTDRD_RUNTIME)
96	        .args(["run", "--rm", image_ref, cmd])
97	        .output()
98	        .map_err(|e| format!("{} run exec failed: {}", RBTDRD_RUNTIME, e))?;
99	    let _ = std::fs::write(dir.join("run-stdout.txt"), &output.stdout);
100	    let _ = std::fs::write(dir.join("run-stderr.txt"), &output.stderr);
101	    if !output.status.success() {
102	        return Err(format!(
103	            "{} run --rm {} {} exited {}: {}",
104	            RBTDRD_RUNTIME,
105	            image_ref,
106	            cmd,
107	            output.status.code().unwrap_or(-1),
108	            String::from_utf8_lossy(&output.stderr).trim()
109	        ));
110	    }
111	    Ok(())
112	}
113	
114	// ── Case ─────────────────────────────────────────────────────
115	
116	fn rbtdrd_build_run_lifecycle(dir: &Path) -> rbtdre_Verdict {
117	    let probe = rbtdrb_Probe {
118	        name: "director RBRA present",
119	        check: rbtdrd_probe_director_rbra,
120	        remediation:
121	            "levy a standing depot and invest a director (canonical-invest or rbw-adI) before this fixture",
122	    };
123	    if let Err(v) = rbtdrb_assert(&probe) {
124	        return v;
125	    }
126	    rbtdrc_with_ctx(|ctx| rbtdrd_build_run_lifecycle_impl(ctx, dir))
127	}
128	
129	fn rbtdrd_build_run_lifecycle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
130	    let vessel_dir = RBTDRC_BUSYBOX_VESSEL_DIR;
131	    if !ctx.project_root().join(vessel_dir).is_dir() {
132	        return rbtdre_Verdict::Fail(format!("vessel directory not found: {}", vessel_dir));
133	    }
134	
135	    // Ordain (conjure-mode): build busybox into the standing depot, capturing
136	    // the hallmark plus the gar_root/ark_stem facts needed to name the
137	    // locally-pulled image after summon.
138	    let _ = std::fs::write(dir.join("01-ordain.txt"), "ordaining busybox");
139	    let ordain = match rbtdri_invoke_global(ctx, RBTDGC_ORDAIN_HALLMARK, &[vessel_dir], &[]) {
140	        Ok(r) if r.exit_code == 0 => r,
141	        Ok(r) => {
142	            return rbtdre_Verdict::Fail(format!("ordain failed (exit {})\n{}", r.exit_code, r.stderr))
143	        }
144	        Err(e) => return rbtdre_Verdict::Fail(format!("ordain invocation: {}", e)),
145	    };
146	    let _ = std::fs::write(dir.join("01-ordain-stdout.txt"), &ordain.stdout);
147	    let hallmark = match rbtdri_read_burv_fact(&ordain, RBTDRC_FACT_HALLMARK) {
148	        Ok(v) => v,
149	        Err(e) => return rbtdre_Verdict::Fail(format!("read hallmark fact: {}", e)),
150	    };
151	    let gar_root = match rbtdri_read_burv_fact(&ordain, RBTDRC_FACT_GAR_ROOT) {
152	        Ok(v) => v,
153	        Err(e) => return rbtdre_Verdict::Fail(format!("read gar_root fact: {}", e)),
154	    };
155	    let ark_stem = match rbtdri_read_burv_fact(&ordain, RBTDRC_FACT_ARK_STEM) {
156	        Ok(v) => v,
157	        Err(e) => return rbtdre_Verdict::Fail(format!("read ark_stem fact: {}", e)),
158	    };
159	    let _ = std::fs::write(dir.join("02-hallmark.txt"), &hallmark);
160	
161	    // The image ref summon pulls locally: <gar_root>/<ark_stem>/image:<hallmark>.
162	    // Same construction onboarding's conjure verification tail uses.
163	    let image_ref = format!(
164	        "{}/{}/{}:{}",
165	        gar_root, ark_stem, RBTDRC_ARK_BASENAME_IMAGE, hallmark
166	    );
167	    let _ = std::fs::write(dir.join("02-image-ref.txt"), &image_ref);
