111	const RBTDRK_ENV_STATION_FILE: &str = "BURD_STATION_FILE";
112	
113	/// Read BURS_TINCTURE from the station file resolved via BURD_STATION_FILE.
114	/// BURS validation upstream (zburs_enforce) guarantees the value is 1-3 chars
115	/// of lowercase alphanumeric starting with a letter.
116	pub(crate) fn rbtdrk_burs_tincture() -> Result<String, String> {
117	    let path_str = std::env::var(RBTDRK_ENV_STATION_FILE)
118	        .map_err(|_| format!("{} not set in environment", RBTDRK_ENV_STATION_FILE))?;
119	    let path = PathBuf::from(&path_str);
120	    rbtdrk_read_env_value(&path, "BURS_TINCTURE")
121	        .ok_or_else(|| format!("BURS_TINCTURE not in {}", path.display()))
122	}
123	
124	/// Compose canonical RBRD_CLOUD_PREFIX with the given tincture.
125	pub(crate) fn rbtdrk_canonical_cloud_prefix(tincture: &str) -> String {
126	    format!("{}{}-", RBTDRK_CANONICAL_CLOUD_BASE, tincture)
127	}
128	
129	/// Compose canonical RBRR_RUNTIME_PREFIX with the given tincture.
130	pub(crate) fn rbtdrk_canonical_runtime_prefix(tincture: &str) -> String {
131	    format!("{}{}-", RBTDRK_CANONICAL_RUNTIME_BASE, tincture)
132	}
133	
134	/// Compose canonical family stem with the given tincture.
