139	// ── Helpers ──────────────────────────────────────────────────
140	
141	/// Read an env-file value or None if absent. Mirrors pristine's helper —
142	/// kept local to avoid coupling canonical-establish to pristine-lifecycle.
143	fn rbtdrk_read_env_value(path: &Path, key: &str) -> Option<String> {
144	    let content = std::fs::read_to_string(path).ok()?;
145	    let prefix = format!("{}=", key);
146	    for line in content.lines() {
147	        let trimmed = line.trim_start();
148	        if trimmed.starts_with('#') {
149	            continue;
150	        }
151	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
152	            return Some(rest.to_string());
153	        }
154	    }
155	    None
156	}
157	
158	fn rbtdrk_resolve(root: &Path, raw: &str) -> PathBuf {
159	    if Path::new(raw).is_absolute() {
160	        PathBuf::from(raw)
161	    } else {
162	        root.join(raw)
163	    }
164	}
165	
166	fn rbtdrk_replace_env_fields(content: &str, pairs: &[(&str, &str)]) -> String {
167	    let mut result: String = content
168	        .lines()
169	        .map(|line| {
170	            for (key, value) in pairs {
171	                let assign = format!("{}=", key);
172	                if line.starts_with(&assign) {
